                     <button onClick={() => setNarrationSource('upload')} className={`flex-1 py-2 text-xs font-bold rounded-md ${narrationSource === 'upload' ? 'bg-cyan-600 text-white' : 'text-slate-400'}`}>Uploads ({uploadedNarrations.length}/10)</button>
