export default SmartPlayer;

import React, { useState, useRef, useEffect } from 'react';
import { Radio, Upload, Play, Pause, SkipForward, Mic2, Clock, Youtube, Trash2, Link, Smartphone, Music, CheckSquare, Square, Lock, Sliders, Volume2, CloudUpload, Repeat, Repeat1, Shuffle, FileAudio, Check, AlertCircle, Loader2 } from 'lucide-react';
import { AudioItem, UserRole } from '../types';
import { isSmartPlayerUnlocked } from '../services/monetizationService';
import { usePlatformDetection } from '../hooks/usePlatformDetection';
import { getCorporatePlaylist, saveCorporatePlaylist } from '../services/corporateService';
import { generateSpeech } from '../services/geminiService';
import { decodeAudioData, audioBufferToWav } from '../utils/audioUtils';
import { VIGNETTE_TEXT } from '../constants';

interface SmartPlayerProps {
  audioContext: AudioContext | null;
  initAudioContext: () => AudioContext;
  narrationHistory: AudioItem[];
  userRole?: UserRole;
}

interface Track {
  id: string;
  type: 'file' | 'youtube' | 'spotify';
  name: string;
  src: string; 
  thumbnail?: string;
}

interface UploadedNarrationFile {
    id: string;
    name: string;
    buffer: AudioBuffer;
}

interface PendingFile {
    name: string;
    buffer: AudioBuffer;
}

declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const SmartPlayer: React.FC<SmartPlayerProps> = ({ audioContext, initAudioContext, narrationHistory, userRole = 'user' }) => {
  const [playlist, setPlaylist] = useState<Track[]>([]);
  const [currentTrackIndex, setCurrentTrackIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isVignettePlaying, setIsVignettePlaying] = useState(false);
  const hasPlayedVignetteRef = useRef(false);
  const vignetteBufferRef = useRef<AudioBuffer | null>(null);

  // Playback Controls
  const [loopMode, setLoopMode] = useState<'off' | 'all' | 'one'>('all');
  const [isShuffle, setIsShuffle] = useState(false);

  const [webInput, setWebInput] = useState('');
  const [intervalSeconds, setIntervalSeconds] = useState(60); 
  const [isSmartEqEnabled, setIsSmartEqEnabled] = useState(true);

  const [narrationSource, setNarrationSource] = useState<'history' | 'upload'>('history');

  // NEW: Multiple Uploads
  const [uploadedNarrations, setUploadedNarrations] = useState<UploadedNarrationFile[]>([]);
  const [pendingUploads, setPendingUploads] = useState<PendingFile[]>([]);
  const [isProcessingUploads, setIsProcessingUploads] = useState(false);

  const [selectedNarrationIds, setSelectedNarrationIds] = useState<string[]>([]);
  const [nextNarrationTimeDisplay, setNextNarrationTimeDisplay] = useState<string>('--:--');
  const [isNarratingUI, setIsNarratingUI] = useState(false);

  const audioElRef = useRef<HTMLAudioElement | null>(null);
  const ytPlayerRef = useRef<any>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const isNarratingRef = useRef(false);
  const nextNarrationTimeRef = useRef<number>(0);
  const hasFadedOutRef = useRef<boolean>(false);
  const timerIntervalRef = useRef<number | null>(null);
  const narrationSourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const fadeIntervalRef = useRef<number | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const { isIOS } = usePlatformDetection();
  const isPremium = isSmartPlayerUnlocked();
  const isCorpAdmin = userRole === 'corporate-admin';
  const isCorpUser = userRole === 'corporate-user';
  const isCorporateMode = isCorpAdmin || isCorpUser;
  const currentTrack = playlist[currentTrackIndex];

  useEffect(() => {
    const ctx = initAudioContext();
    const audio = new Audio();
    audio.crossOrigin = "anonymous";
    audioElRef.current = audio;

    const source = ctx.createMediaElementSource(audio);
    const gain = ctx.createGain();
    gain.gain.value = 1.2; 
    source.connect(gain);
    gain.connect(ctx.destination);
    gainNodeRef.current = gain;

    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
      window.onYouTubeIframeAPIReady = initYoutubePlayer;
    } else {
      initYoutubePlayer();
    }

    if (isCorporateMode) syncCorporatePlaylist();

    return () => {
      audio.pause();
      if (ytPlayerRef.current) try { ytPlayerRef.current.destroy(); } catch(e){}
      stopScheduler();
    };
  }, []);

  useEffect(() => {
    const loadVignette = async () => {
        if (isPremium || hasPlayedVignetteRef.current) return;
        try {
            const ctx = initAudioContext();
            const base64 = await generateSpeech(VIGNETTE_TEXT, 'Kore');
            const buffer = await decodeAudioData(base64, ctx);
            vignetteBufferRef.current = buffer;
        } catch (e) { console.warn("Failed to preload vignette", e); }
    };
    loadVignette();
  }, [isPremium]);

  const syncCorporatePlaylist = () => {
      const corpTracks = getCorporatePlaylist();
      if (corpTracks.length > 0) setPlaylist(corpTracks);
  };

  const handleSaveToCorp = () => {
      if (!isCorpAdmin) return;
      saveCorporatePlaylist(playlist);
      alert("Playlist salva na Nuvem Corporativa!");
  };

  const initYoutubePlayer = () => {
    if (window.YT && window.YT.Player) {
        try {
            ytPlayerRef.current = new window.YT.Player('youtube-player-hidden', {
                height: '0', width: '0',
                events: { 'onStateChange': onPlayerStateChange }
            });
        } catch(e) {}
    }
  };

  const onPlayerStateChange = (event: any) => {
      if (event.data === 0) handleNextTrack();
  };

  useEffect(() => {
    if (!currentTrack) return;
    if (isPlaying && !isVignettePlaying) {
        playTrack(currentTrack);
        startScheduler();
    }
  }, [currentTrackIndex]); 

  // --- CORE PLAY/PAUSE LOGIC ---
  const handleMainPlay = async () => {
      const ctx = initAudioContext();

      if (isPlaying) {
          setIsPlaying(false);
          if (ctx.state === 'running') await ctx.suspend();
          pauseTrack();
          return;
      }

      if (ctx.state === 'suspended') await ctx.resume();

      if (!isPremium && !hasPlayedVignetteRef.current && vignetteBufferRef.current) {
          playVignette();
      } else {
          setIsPlaying(true);
          if (playlist[currentTrackIndex]) playTrack(playlist[currentTrackIndex]);
          startScheduler();
      }
  };

  const playVignette = () => {
      if (!vignetteBufferRef.current) { setIsPlaying(true); return; }
      setIsPlaying(true);
      setIsVignettePlaying(true);
      const ctx = initAudioContext();
      const source = ctx.createBufferSource();
      source.buffer = vignetteBufferRef.current;
      source.connect(ctx.destination);
      source.onended = () => {
          setIsVignettePlaying(false);
          hasPlayedVignetteRef.current = true;
          if (playlist[currentTrackIndex]) playTrack(playlist[currentTrackIndex]);
          startScheduler();
      };
      source.start(0);
  };

  const playTrack = (track: Track) => {
      if (isVignettePlaying) return;
      if (track.type !== 'file') audioElRef.current?.pause();
      if (track.type !== 'youtube') ytPlayerRef.current?.pauseVideo();

      if (isCorpUser && isIOS && track.type === 'youtube') {
          setIsPlaying(false);
          alert("Aviso iOS: YouTube não suporta autoplay. Use Spotify ou Arquivos.");
          return;
      }

      if (track.type === 'file') {
          if (audioElRef.current) {
              if (audioElRef.current.src !== track.src) audioElRef.current.src = track.src;
              if (gainNodeRef.current) gainNodeRef.current.gain.value = 1.2;
              audioElRef.current.play().catch(console.error);
              audioElRef.current.onended = handleNextTrack;
          }
      } else if (track.type === 'youtube') {
          if (ytPlayerRef.current?.loadVideoById) {
               ytPlayerRef.current.loadVideoById(track.src);
               ytPlayerRef.current.setVolume(100);
               ytPlayerRef.current.unMute();
               ytPlayerRef.current.playVideo();
          }
      }
  };

  const pauseTrack = () => {
      audioElRef.current?.pause();
      ytPlayerRef.current?.pauseVideo();
  };

  const handleNextTrack = () => {
      if (playlist.length === 0) return;

      if (loopMode === 'one') {
          // Replay current
          if (currentTrack) {
            if (currentTrack.type === 'file' && audioElRef.current) {
                audioElRef.current.currentTime = 0;
                audioElRef.current.play();
            } else if (currentTrack.type === 'youtube' && ytPlayerRef.current) {
                ytPlayerRef.current.seekTo(0);
                ytPlayerRef.current.playVideo();
            } else {
                playTrack(currentTrack);
            }
          }
          return;
      }

      if (isShuffle) {
          const rand = Math.floor(Math.random() * playlist.length);
          setCurrentTrackIndex(rand);
          return;
      }

      // Normal Loop (All) or Off
      if (currentTrackIndex < playlist.length - 1) {
          setCurrentTrackIndex(prev => prev + 1);
      } else {
          // End of list
          if (loopMode === 'all') {
              setCurrentTrackIndex(0);
          } else {
              setIsPlaying(false); // Stop if loop off
          }
      }
  };

  // --- UPLOAD HANDLER (UPDATED FOR BATCH) ---
  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files.length > 0) {
          const files = Array.from(e.target.files);

          if (files.length > 10) {
              alert("Por favor, selecione no máximo 10 arquivos de uma vez.");
              return;
          }

          setIsProcessingUploads(true);
          const ctx = initAudioContext();
          const newPendingFiles: PendingFile[] = [];

          try {
              for (const file of files) {
                  try {
                      const buffer = await ctx.decodeAudioData(await file.arrayBuffer());
                      newPendingFiles.push({ 
                          name: file.name.replace(/\.[^/.]+$/, ""), 
                          buffer 
                      });
                  } catch(err) {
                      console.error(`Erro ao processar ${file.name}`, err);
                  }
              }

              if (newPendingFiles.length > 0) {
                  setPendingUploads(newPendingFiles);
              } else {
                  alert("Não foi possível processar os arquivos de áudio.");
              }
          } catch (error) {
              alert("Erro durante o upload múltiplo.");
          } finally {
              setIsProcessingUploads(false);
          }
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const confirmUpload = (target: 'playlist' | 'narration') => {
      if (pendingUploads.length === 0) return;

      if (target === 'playlist') {
          const newTracks: Track[] = pendingUploads.map(file => {
              const blob = audioBufferToWav(file.buffer);
              const url = URL.createObjectURL(blob);
              return {
                  id: crypto.randomUUID(),
                  type: 'file',
                  name: file.name,
                  src: url
              };
          });
          setPlaylist(prev => [...prev, ...newTracks]);
      } else {
          // Narration Logic (Limit Check)
          const remainingSlots = 10 - uploadedNarrations.length;
          if (remainingSlots <= 0) {
               alert("Limite de 10 narrações já atingido. Remova algumas antes de adicionar.");
               setPendingUploads([]);
               return;
          }

          let filesToAdd = pendingUploads;
          if (pendingUploads.length > remainingSlots) {
              alert(`Você tem espaço para apenas ${remainingSlots} narrações. Adicionando as primeiras ${remainingSlots}.`);
              filesToAdd = pendingUploads.slice(0, remainingSlots);
          }

          const newNarrations: UploadedNarrationFile[] = filesToAdd.map(file => ({
              id: crypto.randomUUID(),
              name: file.name,
              buffer: file.buffer
          }));

          setUploadedNarrations(prev => [...prev, ...newNarrations]);
          // Auto-select new narrations
          setSelectedNarrationIds(prev => [...prev, ...newNarrations.map(n => n.id)]);
      }
      setPendingUploads([]);
  };

  // --- SCHEDULER & NARRATION LOGIC ---

  const startScheduler = () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      if (nextNarrationTimeRef.current < Date.now()) {
           nextNarrationTimeRef.current = Date.now() + (intervalSeconds * 1000);
           hasFadedOutRef.current = false;
      }
      timerIntervalRef.current = window.setInterval(() => {
          const now = Date.now();
          const remainingMs = nextNarrationTimeRef.current - now;
          const remainingSec = Math.max(0, Math.ceil(remainingMs / 1000));
          setNextNarrationTimeDisplay(remainingSec > 60 ? `${Math.floor(remainingSec/60)}m ${remainingSec%60}s` : `${remainingSec}s`);

          if (remainingMs <= 3500 && remainingMs > 0 && !hasFadedOutRef.current && isPlaying && !isVignettePlaying) {
               lowerVolume(3.0);
               hasFadedOutRef.current = true;
          }
          if (now >= nextNarrationTimeRef.current && !isNarratingRef.current && !isVignettePlaying) {
              playNarration();
          }
      }, 500);
  };

  const stopScheduler = () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };

  const playNarration = () => {
      const ctx = initAudioContext(); 
      let buffer: AudioBuffer | null = null;

      // Randomly pick from ALL selected IDs (History + Uploads)
      const availableIds = selectedNarrationIds.filter(id => {
          const inHistory = narrationHistory.some(n => n.id === id);
          const inUploads = uploadedNarrations.some(u => u.id === id);
          return inHistory || inUploads;
      });

      if (availableIds.length > 0) {
           const randomId = availableIds[Math.floor(Math.random() * availableIds.length)];

           // Find where it is
           const historyItem = narrationHistory.find(n => n.id === randomId);
           if (historyItem) {
               buffer = historyItem.audioData;
           } else {
               const uploadItem = uploadedNarrations.find(u => u.id === randomId);
               if (uploadItem) buffer = uploadItem.buffer;
           }
      }

      if (!buffer) {
          nextNarrationTimeRef.current = Date.now() + (intervalSeconds * 1000);
          hasFadedOutRef.current = false;
          restoreVolume(1.0);
          return;
      }

      isNarratingRef.current = true;
      setIsNarratingUI(true); 

      if (!hasFadedOutRef.current) lowerVolume(0.5);

      const source = ctx.createBufferSource();
      source.buffer = buffer;
      const voiceGain = ctx.createGain();
      voiceGain.gain.value = isSmartEqEnabled ? 1.2 : 1.0; 
      source.connect(voiceGain);
      voiceGain.connect(ctx.destination);
      narrationSourceNodeRef.current = source;

      source.onended = () => {
          isNarratingRef.current = false;
          setIsNarratingUI(false); 
          restoreVolume(3.0);
          nextNarrationTimeRef.current = Date.now() + (intervalSeconds * 1000);
          hasFadedOutRef.current = false;
      };
      source.start(0);
  };

  const lowerVolume = (duration: number = 3.0) => {
      if (!isSmartEqEnabled) return;
      const ctx = initAudioContext();
      if (gainNodeRef.current) {
          gainNodeRef.current.gain.cancelScheduledValues(ctx.currentTime);
          gainNodeRef.current.gain.setValueAtTime(gainNodeRef.current.gain.value, ctx.currentTime);
          gainNodeRef.current.gain.linearRampToValueAtTime(0.15, ctx.currentTime + duration);
      }
      if (ytPlayerRef.current?.setVolume) fadeYouTubeVolume(100, 15, duration * 1000);
  };

  const restoreVolume = (duration: number = 3.0) => {
      if (!isSmartEqEnabled) return;
      const ctx = initAudioContext();
      if (gainNodeRef.current) {
          gainNodeRef.current.gain.cancelScheduledValues(ctx.currentTime);
          gainNodeRef.current.gain.setValueAtTime(gainNodeRef.current.gain.value, ctx.currentTime);
          gainNodeRef.current.gain.linearRampToValueAtTime(1.2, ctx.currentTime + duration);
      }
      if (ytPlayerRef.current?.setVolume) fadeYouTubeVolume(15, 100, duration * 1000);
  };

  const fadeYouTubeVolume = (startVol: number, endVol: number, durationMs: number) => {
      if (!ytPlayerRef.current?.setVolume) return;
      if (fadeIntervalRef.current) clearInterval(fadeIntervalRef.current);
      const steps = 20; const stepTime = durationMs / steps; const volStep = (endVol - startVol) / steps;
      let currentVol = startVol;
      fadeIntervalRef.current = window.setInterval(() => {
          currentVol += volStep;
          if ((volStep > 0 && currentVol >= endVol) || (volStep < 0 && currentVol <= endVol)) {
              currentVol = endVol; clearInterval(fadeIntervalRef.current!);
          }
          try { ytPlayerRef.current.setVolume(currentVol); } catch(e){}
      }, stepTime);
  };

  const addWebLink = () => {
      const trimmedInput = webInput.trim();
      const ytRegExp = /(?:youtube\.com\/(?:[^\/]+\/.+\/|(?:v|e(?:mbed)?)\/|.*[?&]v=|shorts\/|live\/)|youtu\.be\/)([^"&?\/\s]{11})/;
      const spotifyRegExp = /open\.spotify\.com\/(track|album|playlist|episode)\/([a-zA-Z0-9]+)/;
      if (trimmedInput.match(ytRegExp)) {
          const id = trimmedInput.match(ytRegExp)![1];
          setPlaylist(prev => [...prev, { id: crypto.randomUUID(), type: 'youtube', name: `YouTube (${id})`, src: id, thumbnail: `https://img.youtube.com/vi/${id}/0.jpg` }]);
          setWebInput('');
      } else if (trimmedInput.match(spotifyRegExp)) {
          const match = trimmedInput.match(spotifyRegExp)!;
          setPlaylist(prev => [...prev, { id: crypto.randomUUID(), type: 'spotify', name: `Spotify ${match[1]}`, src: `https://open.spotify.com/embed/${match[1]}/${match[2]}?utm_source=generator&theme=0`, thumbnail: '' }]);
          setWebInput('');
      } else { alert("Link inválido."); }
  };
  const getSpotifySrc = () => isPlaying && !isVignettePlaying ? `${currentTrack.src}&autoplay=1` : currentTrack.src;

  const handleToggleNarration = (id: string) => {
      if (selectedNarrationIds.includes(id)) setSelectedNarrationIds(prev => prev.filter(item => item !== id));
      else {
          if (isPremium || isCorporateMode) {
               if (selectedNarrationIds.length >= 20) { alert("Limite de seleção atingido."); return; }
               setSelectedNarrationIds(prev => [...prev, id]);
          } else setSelectedNarrationIds([id]);
      }
  };

  return (
    <div className="max-w-6xl mx-auto w-full px-4 animate-fade-in pb-20 relative">
        <div id="youtube-player-hidden" className="hidden"></div>

        {/* Upload Decision Modal with Batch Support */}
        {pendingUploads.length > 0 && (
            <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-fade-in">
                <div className="bg-slate-900 border border-indigo-500 rounded-2xl p-6 max-w-sm w-full shadow-2xl relative">
                    <button onClick={() => setPendingUploads([])} className="absolute top-4 right-4 text-slate-500 hover:text-white"><AlertCircle size={20} /></button>
                    <h3 className="text-xl font-bold text-white mb-4 flex items-center gap-2">
                        <Upload size={24} className="text-indigo-400" /> Upload de Áudio
                    </h3>
                    <div className="bg-slate-800 p-3 rounded-lg mb-6 text-sm text-slate-300">
                        <p className="font-bold text-white mb-1">
                            {pendingUploads.length > 1 ? `${pendingUploads.length} arquivos selecionados` : pendingUploads[0].name}
                        </p>
                        <p>Onde deseja adicionar {pendingUploads.length > 1 ? 'estes arquivos' : 'este arquivo'}?</p>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <button onClick={() => confirmUpload('playlist')} className="bg-slate-800 hover:bg-slate-700 border border-slate-600 text-white py-4 rounded-xl flex flex-col items-center gap-2 transition-all hover:scale-105 group">
                            <Music size={24} className="text-green-400 group-hover:scale-110 transition-transform" />
                            <span className="text-xs font-bold uppercase">Playlist</span>
                        </button>
                        <button onClick={() => confirmUpload('narration')} className="bg-slate-800 hover:bg-slate-700 border border-slate-600 text-white py-4 rounded-xl flex flex-col items-center gap-2 transition-all hover:scale-105 group">
                            <Mic2 size={24} className="text-cyan-400 group-hover:scale-110 transition-transform" />
                            <span className="text-xs font-bold uppercase">Narrações</span>
                        </button>
                    </div>
                    <button onClick={() => setPendingUploads([])} className="w-full mt-6 text-slate-500 text-xs hover:text-white underline">Cancelar Upload</button>
                </div>
            </div>
        )}

        {/* Upload Processing Loader */}
        {isProcessingUploads && (
             <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/50 backdrop-blur-sm">
                 <div className="bg-slate-900 p-6 rounded-2xl flex flex-col items-center shadow-2xl border border-slate-700">
                     <Loader2 size={48} className="text-cyan-500 animate-spin mb-4" />
                     <p className="text-white font-bold">Processando arquivos...</p>
                 </div>
             </div>
        )}

        <div className="text-center mb-6">
            <h2 className="text-3xl font-bold text-white mb-2 flex items-center justify-center gap-2">
                <Radio className="text-cyan-400" /> Smart Player
                {isCorporateMode && <span className="text-xs bg-indigo-600 text-white px-2 py-1 rounded-full uppercase ml-2">Modo Empresa</span>}
            </h2>
            <div className="flex flex-wrap justify-center gap-2 mt-2">
                {isIOS && <div className="bg-slate-800 border border-yellow-600/50 rounded px-3 py-1 flex items-center gap-2 text-xs text-yellow-500"><Smartphone size={14} /> <span>iOS Detectado: Use <strong>Spotify</strong> ou Arquivos.</span></div>}
            </div>
        </div>

        {/* --- MAIN PLAYER --- */}
        <div className="bg-slate-800/50 border border-slate-700 rounded-3xl p-8 mb-8 relative overflow-hidden min-h-[400px] flex flex-col items-center justify-center transition-all duration-500 group">
             {isVignettePlaying && (
                 <div className="absolute inset-0 z-30 bg-black/90 flex flex-col items-center justify-center animate-fade-in">
                     <Volume2 size={48} className="text-yellow-400 animate-bounce mb-4" />
                     <h3 className="text-2xl font-bold text-white mb-2">VoxGen Audio</h3>
                     <p className="text-slate-400 text-sm italic max-w-md text-center">"{VIGNETTE_TEXT}"</p>
                 </div>
             )}
             <div className={`absolute inset-0 opacity-20 blur-3xl pointer-events-none transition-colors duration-700 ${isNarratingRef.current ? 'bg-cyan-600' : 'bg-gradient-to-br from-cyan-500 to-blue-600'}`} />

             <div className="relative z-10 flex flex-col items-center w-full">
                 {currentTrack?.type === 'spotify' ? (
                     <div className="w-full max-w-md relative flex flex-col items-center">
                         <div className="relative w-full rounded-xl overflow-hidden shadow-2xl bg-black md:h-[352px]">
                             <iframe key={isPlaying ? 'playing' : 'paused'} src={getSpotifySrc()} width="100%" height="100%" frameBorder="0" allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture" loading="lazy" className="w-full h-full min-h-[152px]"></iframe>
                             {!isPlaying && (
                                 <div className="absolute inset-0 z-20 bg-slate-900/95 backdrop-blur-sm flex flex-col items-center justify-center">
                                      <button onClick={handleMainPlay} className="w-20 h-20 bg-cyan-500 rounded-full flex items-center justify-center shadow-[0_0_30px_rgba(6,182,212,0.6)] hover:scale-105 transition-all mb-4 animate-pulse"><Play size={32} fill="black" className="ml-2 text-slate-900" /></button>
                                      <h3 className="text-white font-bold text-lg">Iniciar Sistema</h3>
                                 </div>
                             )}
                             {isNarratingRef.current && (
                                 <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10"><div className="bg-black/80 backdrop-blur-md rounded-2xl p-4 flex flex-col items-center animate-fade-in border border-cyan-500/30"><Mic2 size={32} className="text-cyan-400 animate-pulse mb-2" /><span className="text-cyan-400 font-bold text-xs uppercase">Narrando...</span></div></div>
                             )}
                         </div>
                         {isPlaying && (
                            <div className="mt-6 flex items-center gap-4">
                                 <button onClick={handleMainPlay} className="px-6 py-2 bg-slate-800 hover:bg-red-500/20 text-slate-300 rounded-full text-xs font-bold border border-slate-700 flex items-center gap-2"><Pause size={14} /> Pausar Tudo</button>
                                 <button onClick={handleNextTrack} className="p-2 bg-slate-800 rounded-full text-slate-400 border border-slate-700"><SkipForward size={16} /></button>
                            </div>
                         )}
                     </div>
                 ) : (
                     <>
                        <div className="w-64 h-64 rounded-full border-4 border-slate-700/50 shadow-2xl mb-6 overflow-hidden bg-black flex items-center justify-center relative">
                             {currentTrack ? (
                                 currentTrack.type === 'youtube' ? <img src={currentTrack.thumbnail} className="w-full h-full object-cover" /> : <div className="bg-gradient-to-br from-slate-700 to-slate-800 w-full h-full flex items-center justify-center"><Mic2 size={64} className="text-slate-500 opacity-50" /></div>
                             ) : <div className="text-slate-600">Sem Faixa</div>}
                             {isNarratingRef.current && <div className="absolute inset-0 bg-black/60 flex items-center justify-center backdrop-blur-sm"><Mic2 size={48} className="text-cyan-400 animate-pulse" /></div>}
                        </div>
                        <h3 className="text-xl font-bold text-white mb-1 text-center line-clamp-1 max-w-md">{currentTrack?.name || "Aguardando..."}</h3>

                        <div className="flex items-center gap-6 mt-6">
                             {/* Loop Button */}
                             <button 
                                onClick={() => setLoopMode(prev => prev === 'off' ? 'all' : prev === 'all' ? 'one' : 'off')}
                                className={`p-3 rounded-full transition-all ${loopMode !== 'off' ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500 hover:text-white'}`}
                                title={loopMode === 'all' ? 'Loop Lista' : loopMode === 'one' ? 'Loop Faixa' : 'Sem Loop'}
                             >
                                 {loopMode === 'one' ? <Repeat1 size={18} /> : <Repeat size={18} />}
                             </button>

                             <button onClick={handleMainPlay} disabled={playlist.length === 0} className={`w-20 h-20 rounded-full flex items-center justify-center transition-all ${isPlaying ? 'bg-cyan-500 text-black shadow-[0_0_30px_rgba(6,182,212,0.5)] scale-105' : 'bg-slate-700 text-white hover:bg-slate-600'}`}>
                                 {isPlaying ? <Pause size={32} fill="black" /> : <Play size={32} fill="white" className="ml-2" />}
                             </button>

                             <button onClick={handleNextTrack} className="p-4 rounded-full bg-slate-800 text-slate-400 hover:text-white"><SkipForward size={24} /></button>

                             {/* Shuffle Button */}
                             <button 
                                onClick={() => setIsShuffle(!isShuffle)}
                                className={`p-3 rounded-full transition-all ${isShuffle ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500 hover:text-white'}`}
                                title="Aleatório"
                             >
                                 <Shuffle size={18} />
                             </button>
                         </div>
                     </>
                 )}
                 <div className="mt-8 bg-black/30 px-6 py-2 rounded-full border border-white/5 flex items-center gap-3">
                     <Clock size={14} className="text-cyan-400" />
                     <span className="text-xs text-slate-400">Próxima Narração:</span>
                     <span className="text-sm font-mono font-bold text-white w-16 text-center">{isPlaying ? nextNarrationTimeDisplay : '--:--'}</span>
                 </div>
             </div>
        </div>

        {/* --- MANAGERS --- */}
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className="bg-slate-900/50 border border-slate-800 rounded-2xl p-6 relative">
                {isCorpUser && <div className="absolute inset-0 z-10 bg-slate-900/80 backdrop-blur-[1px] flex flex-col items-center justify-center rounded-2xl border border-indigo-500/30"><Lock className="text-indigo-400 mb-2" size={32} /><p className="text-indigo-200 font-bold">Playlist da Empresa</p></div>}

                <div className="flex justify-between items-center mb-4">
                    <h4 className="text-white font-bold flex items-center gap-2"><Upload size={18} className="text-purple-400" /> Playlist</h4>
                    {isCorpAdmin && <button onClick={handleSaveToCorp} className="text-xs bg-indigo-600 text-white px-3 py-1 rounded flex items-center gap-1"><CloudUpload size={12}/> Salvar</button>}
                </div>

                <div className="space-y-4 mb-6">
                    <div className="flex gap-2">
                        <input type="text" value={webInput} onChange={(e) => setWebInput(e.target.value)} placeholder="YouTube / Spotify Link..." className="w-full bg-slate-800 border border-slate-700 rounded-lg py-2 px-4 text-sm text-white focus:border-cyan-500 outline-none" />
                        <button onClick={addWebLink} className="bg-indigo-600 hover:bg-indigo-500 text-white px-4 rounded-lg"><Link size={18} /></button>

                        {/* GENERAL UPLOAD BUTTON */}
                        <div className="relative">
                            <button 
                                onClick={() => fileInputRef.current?.click()} 
                                className="bg-slate-700 hover:bg-slate-600 text-white px-4 rounded-lg h-full flex items-center justify-center"
                                title="Upload de Arquivo (Música ou Narração)"
                            >
                                <FileAudio size={18} />
                            </button>
                            {/* UPDATED INPUT: multiple support */}
                            <input ref={fileInputRef} type="file" accept="audio/*" multiple className="hidden" onChange={handleFileSelect} />
                        </div>
                    </div>
                </div>

                <div className="h-64 overflow-y-auto custom-scrollbar space-y-2 pr-2">
                    {playlist.length === 0 && <p className="text-center text-slate-500 text-sm py-4">Sua playlist está vazia.</p>}
                    {playlist.map((track, idx) => (
                        <div key={track.id} className={`flex items-center justify-between p-3 rounded-lg text-sm ${idx === currentTrackIndex ? 'bg-cyan-900/20 border border-cyan-500/30 text-cyan-200' : 'bg-slate-800 text-slate-300'}`}>
                            <div className="flex items-center gap-3 truncate">
                                {track.type === 'youtube' ? <Youtube size={14} className="text-red-400 flex-shrink-0" /> : <Music size={14} className="text-green-400 flex-shrink-0" />}
                                <span className="truncate max-w-[180px]">{track.name}</span>
                            </div>
                            <button onClick={() => { const newPl = [...playlist]; newPl.splice(idx, 1); setPlaylist(newPl); }} className="text-slate-500 hover:text-red-400"><Trash2 size={14} /></button>
                        </div>
                    ))}
                </div>
            </div>

            <div className="bg-slate-900/50 border border-slate-800 rounded-2xl p-6 relative">
                 {isCorpUser && !isPremium && <div className="absolute inset-0 z-10 bg-slate-900/80 backdrop-blur-[1px] flex flex-col items-center justify-center rounded-2xl border border-indigo-500/30"><Lock className="text-indigo-400 mb-2" size={32} /><p className="text-indigo-200 font-bold">Narração Bloqueada</p></div>}

                 <div className="flex justify-between items-center mb-4">
                     <h4 className="text-white font-bold flex items-center gap-2"><Mic2 size={18} className="text-cyan-400" /> Narração</h4>
                 </div>

                 <div className="flex bg-slate-800 p-1 rounded-lg mb-6">
                     <button onClick={() => setNarrationSource('history')} className={`flex-1 py-2 text-xs font-bold rounded-md ${narrationSource === 'history' ? 'bg-cyan-600 text-white' : 'text-slate-400'}`}>Histórico IA</button>
                     <button onClick={() => setNarrationSource('upload')} className={`flex-1 py-2 text-xs font-bold rounded-md ${narrationSource === 'upload' ? 'bg-cyan-600 text-white' : 'text-slate-400'}`}>Uploads ({uploadedNarrations.length}/10)</button>
                 </div>

                 {narrationSource === 'history' ? (
                     <div className="w-full bg-slate-800 border border-slate-700 rounded-lg max-h-48 overflow-y-auto custom-scrollbar p-2 space-y-1">
                         {narrationHistory.length === 0 && <p className="text-center text-slate-500 text-xs py-4">Gere narrações para vê-las aqui.</p>}
                         {narrationHistory.map(n => { 
                             const isSelected = selectedNarrationIds.includes(n.id); 
                             return (
                                 <div key={n.id} onClick={() => handleToggleNarration(n.id)} className={`flex items-start gap-3 p-2 rounded cursor-pointer text-xs ${isSelected ? 'bg-cyan-900/30 border border-cyan-500/30' : 'hover:bg-slate-700 border border-transparent'}`}>
                                     <div className={`mt-0.5 ${isSelected ? 'text-cyan-400' : 'text-slate-600'}`}>{isSelected ? <CheckSquare size={14} /> : <Square size={14} />}</div>
                                     <div className="flex-grow"><p className={`line-clamp-2 ${isSelected ? 'text-cyan-100' : 'text-slate-400'}`}>{n.text}</p></div>
                                 </div>
                             ); 
                         })}
                     </div>
                 ) : (
                     <div className="w-full bg-slate-800 border border-slate-700 rounded-lg max-h-48 overflow-y-auto custom-scrollbar p-2 space-y-1">
                         {uploadedNarrations.length === 0 && (
                             <div className="text-center py-6 text-slate-500">
                                 <p className="text-xs mb-2">Nenhum upload.</p>
                                 <button onClick={() => fileInputRef.current?.click()} className="text-cyan-400 hover:underline text-xs">Clique no botão de arquivo acima</button>
                             </div>
                         )}
                         {uploadedNarrations.map(u => {
                             const isSelected = selectedNarrationIds.includes(u.id);
                             return (
                                 <div key={u.id} className={`flex items-center gap-3 p-2 rounded cursor-pointer text-xs ${isSelected ? 'bg-cyan-900/30 border border-cyan-500/30' : 'hover:bg-slate-700 border border-transparent'}`}>
                                     <div onClick={() => handleToggleNarration(u.id)} className={`flex-shrink-0 ${isSelected ? 'text-cyan-400' : 'text-slate-600'}`}>
                                         {isSelected ? <CheckSquare size={14} /> : <Square size={14} />}
                                     </div>
                                     <div className="flex-grow truncate text-slate-300" onClick={() => handleToggleNarration(u.id)}>{u.name}</div>
                                     <button onClick={() => {
                                         setUploadedNarrations(prev => prev.filter(x => x.id !== u.id));
                                         setSelectedNarrationIds(prev => prev.filter(id => id !== u.id));
                                     }} className="text-slate-500 hover:text-red-400"><Trash2 size={12} /></button>
                                 </div>
                             );
                         })}
                     </div>
                 )}
                 <div className="mt-2 text-[10px] text-slate-500 flex justify-between">
                     <span>Selecione múltiplos itens para alternar aleatoriamente.</span>
                     <span>{selectedNarrationIds.filter(id => narrationSource === 'history' ? narrationHistory.some(n => n.id === id) : uploadedNarrations.some(u => u.id === id)).length} selecionados</span>
                 </div>

                 <div className="mt-6"><div className="flex justify-between mb-2"><label className="text-xs text-slate-400">Intervalo</label><span className="text-xs font-bold text-cyan-400">{intervalSeconds}s</span></div><input type="range" min="5" max="180" step="5" value={intervalSeconds} onChange={(e) => setIntervalSeconds(parseInt(e.target.value))} className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-cyan-500" /></div>

                 {/* SMART EQ */}
                 <div className="mt-6 border-t border-slate-800 pt-4">
                    <div className="flex items-center justify-between mb-2">
                        <label className="text-xs font-bold text-slate-400 flex items-center gap-2">
                            <Sliders size={14} /> Equalizador & Fader
                        </label>
                        <button 
                            onClick={() => setIsSmartEqEnabled(!isSmartEqEnabled)}
                            className={`text-[10px] px-2 py-1 rounded-full font-bold transition-colors ${isSmartEqEnabled ? 'bg-green-500/20 text-green-400' : 'bg-slate-700 text-slate-400'}`}
                        >
                            {isSmartEqEnabled ? 'ON' : 'OFF'}
                        </button>
                    </div>
                    <div className="bg-slate-950 rounded-lg p-3 space-y-3">
                        <div className="flex items-center gap-3">
                            <Music size={12} className="text-slate-500" />
                            <div className="flex-grow h-1.5 bg-slate-800 rounded-full overflow-hidden">
                                <div className={`h-full rounded-full transition-all duration-[3000ms] ease-in-out ${isNarratingUI && isSmartEqEnabled ? 'w-[15%] bg-yellow-600' : 'w-[100%] bg-green-500'}`} />
                            </div>
                            <span className="text-[10px] text-slate-500 w-8 text-right">{isNarratingUI && isSmartEqEnabled ? '15%' : '120%'}</span>
                        </div>
                        <div className="flex items-center gap-3">
                            <Mic2 size={12} className="text-slate-500" />
                            <div className="flex-grow h-1.5 bg-slate-800 rounded-full overflow-hidden">
                                <div className={`h-full bg-cyan-500 rounded-full transition-all duration-500 ${isNarratingUI ? 'w-[100%]' : 'w-0'}`} />
                            </div>
                            <span className="text-[10px] text-slate-500 w-8 text-right">120%</span>
                        </div>
                        <p className="text-[10px] text-slate-500 italic mt-1 text-center">
                            {isSmartEqEnabled ? "Fade Out (3s) antes da fala. Fade In (3s) depois." : "Volumes independentes."}
                        </p>
                    </div>
                </div>

            </div>
        </div>
    </div>
  );
};

export default SmartPlayer;

import React, { useState, useRef, useEffect } from 'react';
import { Radio, Upload, Play, Pause, SkipForward, Mic2, Clock, Youtube, Trash2, Link, Smartphone, Music, CheckSquare, Square, Lock, Sliders, Volume2, CloudUpload, Repeat, Repeat1, Shuffle, FileAudio, Check, AlertCircle, Loader2 } from 'lucide-react';
import { AudioItem, UserRole } from '../types';
import { isSmartPlayerUnlocked } from '../services/monetizationService';
import { usePlatformDetection } from '../hooks/usePlatformDetection';
import { getCorporatePlaylist, saveCorporatePlaylist } from '../services/corporateService';
import { generateSpeech } from '../services/geminiService';
import { decodeAudioData, audioBufferToWav } from '../utils/audioUtils';
import { VIGNETTE_TEXT } from '../constants';

interface SmartPlayerProps {
  audioContext: AudioContext | null;
  initAudioContext: () => AudioContext;
  narrationHistory: AudioItem[];
  userRole?: UserRole;
}

interface Track {
  id: string;
  type: 'file' | 'youtube' | 'spotify';
  name: string;
  src: string; 
  thumbnail?: string;
}

interface UploadedNarrationFile {
    id: string;
    name: string;
    buffer: AudioBuffer;
}

interface PendingFile {
    name: string;
    buffer: AudioBuffer;
}

declare global {
  interface Window {
    onYouTubeIframeAPIReady: () => void;
    YT: any;
  }
}

const SmartPlayer: React.FC<SmartPlayerProps> = ({ audioContext, initAudioContext, narrationHistory, userRole = 'user' }) => {
  const [playlist, setPlaylist] = useState<Track[]>([]);
  const [currentTrackIndex, setCurrentTrackIndex] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isVignettePlaying, setIsVignettePlaying] = useState(false);
  const hasPlayedVignetteRef = useRef(false);
  const vignetteBufferRef = useRef<AudioBuffer | null>(null);

  // Playback Controls
  const [loopMode, setLoopMode] = useState<'off' | 'all' | 'one'>('all');
  const [isShuffle, setIsShuffle] = useState(false);

  const [webInput, setWebInput] = useState('');
  const [intervalSeconds, setIntervalSeconds] = useState(60); 
  const [isSmartEqEnabled, setIsSmartEqEnabled] = useState(true);

  const [narrationSource, setNarrationSource] = useState<'history' | 'upload'>('history');

  // NEW: Multiple Uploads
  const [uploadedNarrations, setUploadedNarrations] = useState<UploadedNarrationFile[]>([]);
  const [pendingUploads, setPendingUploads] = useState<PendingFile[]>([]);
  const [isProcessingUploads, setIsProcessingUploads] = useState(false);

  const [selectedNarrationIds, setSelectedNarrationIds] = useState<string[]>([]);
  const [nextNarrationTimeDisplay, setNextNarrationTimeDisplay] = useState<string>('--:--');
  const [isNarratingUI, setIsNarratingUI] = useState(false);

  const audioElRef = useRef<HTMLAudioElement | null>(null);
  const ytPlayerRef = useRef<any>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const isNarratingRef = useRef(false);
  const nextNarrationTimeRef = useRef<number>(0);
  const hasFadedOutRef = useRef<boolean>(false);
  const timerIntervalRef = useRef<number | null>(null);
  const narrationSourceNodeRef = useRef<AudioBufferSourceNode | null>(null);
  const fadeIntervalRef = useRef<number | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const { isIOS } = usePlatformDetection();
  const isPremium = isSmartPlayerUnlocked();
  const isCorpAdmin = userRole === 'corporate-admin';
  const isCorpUser = userRole === 'corporate-user';
  const isCorporateMode = isCorpAdmin || isCorpUser;
  const currentTrack = playlist[currentTrackIndex];

  useEffect(() => {
    const ctx = initAudioContext();
    const audio = new Audio();
    audio.crossOrigin = "anonymous";
    audioElRef.current = audio;

    const source = ctx.createMediaElementSource(audio);
    const gain = ctx.createGain();
    gain.gain.value = 1.2; 
    source.connect(gain);
    gain.connect(ctx.destination);
    gainNodeRef.current = gain;

    if (!window.YT) {
      const tag = document.createElement('script');
      tag.src = "https://www.youtube.com/iframe_api";
      const firstScriptTag = document.getElementsByTagName('script')[0];
      firstScriptTag.parentNode?.insertBefore(tag, firstScriptTag);
      window.onYouTubeIframeAPIReady = initYoutubePlayer;
    } else {
      initYoutubePlayer();
    }

    if (isCorporateMode) syncCorporatePlaylist();

    return () => {
      audio.pause();
      if (ytPlayerRef.current) try { ytPlayerRef.current.destroy(); } catch(e){}
      stopScheduler();
    };
  }, []);

  useEffect(() => {
    const loadVignette = async () => {
        if (isPremium || hasPlayedVignetteRef.current) return;
        try {
            const ctx = initAudioContext();
            const base64 = await generateSpeech(VIGNETTE_TEXT, 'Kore');
            const buffer = await decodeAudioData(base64, ctx);
            vignetteBufferRef.current = buffer;
        } catch (e) { console.warn("Failed to preload vignette", e); }
    };
    loadVignette();
  }, [isPremium]);

  const syncCorporatePlaylist = () => {
      const corpTracks = getCorporatePlaylist();
      if (corpTracks.length > 0) setPlaylist(corpTracks);
  };

  const handleSaveToCorp = () => {
      if (!isCorpAdmin) return;
      saveCorporatePlaylist(playlist);
      alert("Playlist salva na Nuvem Corporativa!");
  };

  const initYoutubePlayer = () => {
    if (window.YT && window.YT.Player) {
        try {
            ytPlayerRef.current = new window.YT.Player('youtube-player-hidden', {
                height: '0', width: '0',
                events: { 'onStateChange': onPlayerStateChange }
            });
        } catch(e) {}
    }
  };

  const onPlayerStateChange = (event: any) => {
      if (event.data === 0) handleNextTrack();
  };

  useEffect(() => {
    if (!currentTrack) return;
    if (isPlaying && !isVignettePlaying) {
        playTrack(currentTrack);
        startScheduler();
    }
  }, [currentTrackIndex]); 

  // --- CORE PLAY/PAUSE LOGIC ---
  const handleMainPlay = async () => {
      const ctx = initAudioContext();

      if (isPlaying) {
          setIsPlaying(false);
          if (ctx.state === 'running') await ctx.suspend();
          pauseTrack();
          return;
      }

      if (ctx.state === 'suspended') await ctx.resume();

      if (!isPremium && !hasPlayedVignetteRef.current && vignetteBufferRef.current) {
          playVignette();
      } else {
          setIsPlaying(true);
          if (playlist[currentTrackIndex]) playTrack(playlist[currentTrackIndex]);
          startScheduler();
      }
  };

  const playVignette = () => {
      if (!vignetteBufferRef.current) { setIsPlaying(true); return; }
      setIsPlaying(true);
      setIsVignettePlaying(true);
      const ctx = initAudioContext();
      const source = ctx.createBufferSource();
      source.buffer = vignetteBufferRef.current;
      source.connect(ctx.destination);
      source.onended = () => {
          setIsVignettePlaying(false);
          hasPlayedVignetteRef.current = true;
          if (playlist[currentTrackIndex]) playTrack(playlist[currentTrackIndex]);
          startScheduler();
      };
      source.start(0);
  };

  const playTrack = (track: Track) => {
      if (isVignettePlaying) return;
      if (track.type !== 'file') audioElRef.current?.pause();
      if (track.type !== 'youtube') ytPlayerRef.current?.pauseVideo();

      if (isCorpUser && isIOS && track.type === 'youtube') {
          setIsPlaying(false);
          alert("Aviso iOS: YouTube não suporta autoplay. Use Spotify ou Arquivos.");
          return;
      }

      if (track.type === 'file') {
          if (audioElRef.current) {
              if (audioElRef.current.src !== track.src) audioElRef.current.src = track.src;
              if (gainNodeRef.current) gainNodeRef.current.gain.value = 1.2;
              audioElRef.current.play().catch(console.error);
              audioElRef.current.onended = handleNextTrack;
          }
      } else if (track.type === 'youtube') {
          if (ytPlayerRef.current?.loadVideoById) {
               ytPlayerRef.current.loadVideoById(track.src);
               ytPlayerRef.current.setVolume(100);
               ytPlayerRef.current.unMute();
               ytPlayerRef.current.playVideo();
          }
      }
  };

  const pauseTrack = () => {
      audioElRef.current?.pause();
      ytPlayerRef.current?.pauseVideo();
  };

  const handleNextTrack = () => {
      if (playlist.length === 0) return;

      if (loopMode === 'one') {
          // Replay current
          if (currentTrack) {
            if (currentTrack.type === 'file' && audioElRef.current) {
                audioElRef.current.currentTime = 0;
                audioElRef.current.play();
            } else if (currentTrack.type === 'youtube' && ytPlayerRef.current) {
                ytPlayerRef.current.seekTo(0);
                ytPlayerRef.current.playVideo();
            } else {
                playTrack(currentTrack);
            }
          }
          return;
      }

      if (isShuffle) {
          const rand = Math.floor(Math.random() * playlist.length);
          setCurrentTrackIndex(rand);
          return;
      }

      // Normal Loop (All) or Off
      if (currentTrackIndex < playlist.length - 1) {
          setCurrentTrackIndex(prev => prev + 1);
      } else {
          // End of list
          if (loopMode === 'all') {
              setCurrentTrackIndex(0);
          } else {
              setIsPlaying(false); // Stop if loop off
          }
      }
  };

  // --- UPLOAD HANDLER (UPDATED FOR BATCH) ---
  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files.length > 0) {
          const files: File[] = Array.from(e.target.files);

          if (files.length > 10) {
              alert("Por favor, selecione no máximo 10 arquivos de uma vez.");
              return;
          }

          setIsProcessingUploads(true);
          const ctx = initAudioContext();
          const newPendingFiles: PendingFile[] = [];

          try {
              for (const file of files) {
                  try {
                      const buffer = await ctx.decodeAudioData(await file.arrayBuffer());
                      newPendingFiles.push({ 
                          name: file.name.replace(/\.[^/.]+$/, ""), 
                          buffer 
                      });
                  } catch(err) {
                      console.error(`Erro ao processar ${file.name}`, err);
                  }
              }

              if (newPendingFiles.length > 0) {
                  setPendingUploads(newPendingFiles);
              } else {
                  alert("Não foi possível processar os arquivos de áudio.");
              }
          } catch (error) {
              alert("Erro durante o upload múltiplo.");
          } finally {
              setIsProcessingUploads(false);
          }
      }
      if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const confirmUpload = (target: 'playlist' | 'narration') => {
      if (pendingUploads.length === 0) return;

      if (target === 'playlist') {
          const newTracks: Track[] = pendingUploads.map(file => {
              const blob = audioBufferToWav(file.buffer);
              const url = URL.createObjectURL(blob);
              return {
                  id: crypto.randomUUID(),
                  type: 'file',
                  name: file.name,
                  src: url
              };
          });
          setPlaylist(prev => [...prev, ...newTracks]);
      } else {
          // Narration Logic (Limit Check)
          const remainingSlots = 10 - uploadedNarrations.length;
          if (remainingSlots <= 0) {
               alert("Limite de 10 narrações já atingido. Remova algumas antes de adicionar.");
               setPendingUploads([]);
               return;
          }

          let filesToAdd = pendingUploads;
          if (pendingUploads.length > remainingSlots) {
              alert(`Você tem espaço para apenas ${remainingSlots} narrações. Adicionando as primeiras ${remainingSlots}.`);
              filesToAdd = pendingUploads.slice(0, remainingSlots);
          }

          const newNarrations: UploadedNarrationFile[] = filesToAdd.map(file => ({
              id: crypto.randomUUID(),
              name: file.name,
              buffer: file.buffer
          }));

          setUploadedNarrations(prev => [...prev, ...newNarrations]);
          // Auto-select new narrations
          setSelectedNarrationIds(prev => [...prev, ...newNarrations.map(n => n.id)]);
      }
      setPendingUploads([]);
  };

  // --- SCHEDULER & NARRATION LOGIC ---

  const startScheduler = () => {
      if (timerIntervalRef.current) clearInterval(timerIntervalRef.current);
      if (nextNarrationTimeRef.current < Date.now()) {
           nextNarrationTimeRef.current = Date.now() + (intervalSeconds * 1000);
           hasFadedOutRef.current = false;
      }
      timerIntervalRef.current = window.setInterval(() => {
          const now = Date.now();
          const remainingMs = nextNarrationTimeRef.current - now;
          const remainingSec = Math.max(0, Math.ceil(remainingMs / 1000));
          setNextNarrationTimeDisplay(remainingSec > 60 ? `${Math.floor(remainingSec/60)}m ${remainingSec%60}s` : `${remainingSec}s`);

          if (remainingMs <= 3500 && remainingMs > 0 && !hasFadedOutRef.current && isPlaying && !isVignettePlaying) {
               lowerVolume(3.0);
               hasFadedOutRef.current = true;
          }
          if (now >= nextNarrationTimeRef.current && !isNarratingRef.current && !isVignettePlaying) {
              playNarration();
          }
      }, 500);
  };

  const stopScheduler = () => { if (timerIntervalRef.current) clearInterval(timerIntervalRef.current); };

  const playNarration = () => {
      const ctx = initAudioContext(); 
      let buffer: AudioBuffer | null = null;

      // Randomly pick from ALL selected IDs (History + Uploads)
      const availableIds = selectedNarrationIds.filter(id => {
          const inHistory = narrationHistory.some(n => n.id === id);
          const inUploads = uploadedNarrations.some(u => u.id === id);
          return inHistory || inUploads;
      });

      if (availableIds.length > 0) {
           const randomId = availableIds[Math.floor(Math.random() * availableIds.length)];

           // Find where it is
           const historyItem = narrationHistory.find(n => n.id === randomId);
           if (historyItem) {
               buffer = historyItem.audioData;
           } else {
               const uploadItem = uploadedNarrations.find(u => u.id === randomId);
               if (uploadItem) buffer = uploadItem.buffer;
           }
      }

      if (!buffer) {
          nextNarrationTimeRef.current = Date.now() + (intervalSeconds * 1000);
          hasFadedOutRef.current = false;
          restoreVolume(1.0);
          return;
      }

      isNarratingRef.current = true;
      setIsNarratingUI(true); 

      if (!hasFadedOutRef.current) lowerVolume(0.5);

      const source = ctx.createBufferSource();
      source.buffer = buffer;
      const voiceGain = ctx.createGain();
      voiceGain.gain.value = isSmartEqEnabled ? 1.2 : 1.0; 
      source.connect(voiceGain);
      voiceGain.connect(ctx.destination);
      narrationSourceNodeRef.current = source;

      source.onended = () => {
          isNarratingRef.current = false;
          setIsNarratingUI(false); 
          restoreVolume(3.0);
          nextNarrationTimeRef.current = Date.now() + (intervalSeconds * 1000);
          hasFadedOutRef.current = false;
      };
      source.start(0);
  };

  const lowerVolume = (duration: number = 3.0) => {
      if (!isSmartEqEnabled) return;
      const ctx = initAudioContext();
      if (gainNodeRef.current) {
          gainNodeRef.current.gain.cancelScheduledValues(ctx.currentTime);
          gainNodeRef.current.gain.setValueAtTime(gainNodeRef.current.gain.value, ctx.currentTime);
          gainNodeRef.current.gain.linearRampToValueAtTime(0.15, ctx.currentTime + duration);
      }
      if (ytPlayerRef.current?.setVolume) fadeYouTubeVolume(100, 15, duration * 1000);
  };

  const restoreVolume = (duration: number = 3.0) => {
      if (!isSmartEqEnabled) return;
      const ctx = initAudioContext();
      if (gainNodeRef.current) {
          gainNodeRef.current.gain.cancelScheduledValues(ctx.currentTime);
          gainNodeRef.current.gain.setValueAtTime(gainNodeRef.current.gain.value, ctx.currentTime);
          gainNodeRef.current.gain.linearRampToValueAtTime(1.2, ctx.currentTime + duration);
      }
      if (ytPlayerRef.current?.setVolume) fadeYouTubeVolume(15, 100, duration * 1000);
  };

  const fadeYouTubeVolume = (startVol: number, endVol: number, durationMs: number) => {
      if (!ytPlayerRef.current?.setVolume) return;
      if (fadeIntervalRef.current) clearInterval(fadeIntervalRef.current);
      const steps = 20; const stepTime = durationMs / steps; const volStep = (endVol - startVol) / steps;
      let currentVol = startVol;
      fadeIntervalRef.current = window.setInterval(() => {
          currentVol += volStep;
          if ((volStep > 0 && currentVol >= endVol) || (volStep < 0 && currentVol <= endVol)) {
              currentVol = endVol; clearInterval(fadeIntervalRef.current!);
          }
          try { ytPlayerRef.current.setVolume(currentVol); } catch(e){}
      }, stepTime);
  };

  const addWebLink = () => {
      const trimmedInput = webInput.trim();
      const ytRegExp = /(?:youtube\.com\/(?:[^\/]+\/.+\/|(?:v|e(?:mbed)?)\/|.*[?&]v=|shorts\/|live\/)|youtu\.be\/)([^"&?\/\s]{11})/;
      const spotifyRegExp = /open\.spotify\.com\/(track|album|playlist|episode)\/([a-zA-Z0-9]+)/;
      if (trimmedInput.match(ytRegExp)) {
          const id = trimmedInput.match(ytRegExp)![1];
          setPlaylist(prev => [...prev, { id: crypto.randomUUID(), type: 'youtube', name: `YouTube (${id})`, src: id, thumbnail: `https://img.youtube.com/vi/${id}/0.jpg` }]);
          setWebInput('');
      } else if (trimmedInput.match(spotifyRegExp)) {
          const match = trimmedInput.match(spotifyRegExp)!;
          setPlaylist(prev => [...prev, { id: crypto.randomUUID(), type: 'spotify', name: `Spotify ${match[1]}`, src: `https://open.spotify.com/embed/${match[1]}/${match[2]}?utm_source=generator&theme=0`, thumbnail: '' }]);
          setWebInput('');
      } else { alert("Link inválido."); }
  };
