import { GoogleGenAI, Type, Modality } from "@google/genai";
import { ToneType, VoiceName, CustomVoice } from "../types";
import { generateProceduralSFX, concatenateAudioBuffers, decodeAudioData } from "../utils/audioUtils";
import { SFX_COMMANDS_HELP } from "../constants";

const STORAGE_KEYS = {
  CUSTOM_VOICES: 'voxgen_custom_voices_v1'
};

const getClient = () => {
  const rawKey = process.env.API_KEY || "";
  const cleanKey = rawKey.replace(/["'\s]/g, ""); 
  return new GoogleGenAI({ apiKey: cleanKey });
};

// Helper para espera (delay)
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

// ... helpers (getCustomVoiceById, getMimeTypeFromBase64) mantidos ou importados ...
const getCustomVoiceById = (id: string): CustomVoice | undefined => {
    try {
      const data = localStorage.getItem(STORAGE_KEYS.CUSTOM_VOICES);
      const voices: CustomVoice[] = data ? JSON.parse(data) : [];
      return voices.find(v => v.id === id);
    } catch (e) {
      return undefined;
    }
};

const getMimeTypeFromBase64 = (base64String: string, defaultType: string = 'audio/wav'): string => {
    if (!base64String || !base64String.startsWith('data:')) return defaultType;
    const matches = base64String.match(/^data:([a-zA-Z0-9]+\/[a-zA-Z0-9-.+]+).*,/);
    return matches && matches[1] ? matches[1] : defaultType;
};

const cleanTextForSpeech = (text: string): string => {
  // NÃO removemos mais parênteses aqui pois eles são SFX agora.
  // Apenas removemos tags < > que não são suportadas ou são controle interno antigo
  return text
    .replace(/<.*?>/g, "")   
    .replace(/\s+/g, " ")    
    .trim();
};

export const refineText = async (text: string, tone: ToneType | string, useBackgroundMusic: boolean): Promise<string> => {
  if (tone === ToneType.Neutral && !useBackgroundMusic && !text.match(/[\(<]/)) return text;

  const ai = getClient();
  let specificInstruction = "";

  if (useBackgroundMusic) {
    specificInstruction += " O usuário solicitou fundo musical. Adapte o ritmo. ";
  }

  if (tone === 'Vignette') {
      specificInstruction += " ESTILO VINHETA DE RÁDIO: Use linguagem impactante, curta e direta. INSERIR EFEITOS SONOROS. ";
      specificInstruction += " Use tags entre PARÊNTESES como (buzina) para atenção, (explosao) para impacto, (aplausos) para conquistas. ";
  } else if (tone === ToneType.Sales) {
      specificInstruction += " ESTILO VENDAS: Urgente. Sugira uso de (caixa) ou (buzina). ";
  } else if (tone === ToneType.Dramatic) {
      specificInstruction += " ESTILO DRAMÁTICO: Use pausas e emoção. ";
  }

  const prompt = `
    Você é um roteirista de áudio profissional (PT-BR) da VoxGen.
    Tarefa: Humanizar o texto para o tom: "${tone}".

    IMPORTANTE - EFEITOS SONOROS (SFX):
    Você DEVE inserir comandos de efeitos sonoros entre PARÊNTESES onde fizer sentido para o contexto.
    Comandos aceitos: (buzina), (explosao), (aplausos), (risada), (caixa), (laser), (motor), (transito), (coin).

    Exemplo: "Atenção (buzina) chegou a hora! (explosao)"

    REGRAS:
    1. Mantenha a mensagem original.
    2. Retorne APENAS o texto final. Sem "Aqui está".

    Texto Original: "${text}"
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    let cleanedText = response.text?.trim() || text;
    cleanedText = cleanedText.replace(/^(Aqui está|Segue|Texto adaptado|Reescrita|Versão humanizada).*?:/i, "").trim();
    cleanedText = cleanedText.replace(/^["']|["']$/g, "").trim();
    return cleanedText;
  } catch (e) {
    return text; 
  }
};

/**
 * Analisa o texto e insere automaticamente efeitos sonoros baseados no contexto.
 */
export const addAutomaticSFX = async (text: string): Promise<string> => {
  if (!text.trim()) return text;

  const ai = getClient();
  const availableSFX = SFX_COMMANDS_HELP.join(', ');

  const prompt = `
    Você é um Editor de Áudio Inteligente (Sound Designer).

    TAREFA:
    Analise o texto abaixo e insira tags de efeitos sonoros onde eles aumentam dramaticamente a imersão ou enfatizam a ação.

    TAGS DISPONÍVEIS:
    ${availableSFX}

    REGRAS:
    1. Mantenha o texto original exatamente como está (não reescreva, apenas insira tags).
    2. Insira as tags entre parênteses, ex: "Eu ganhei! (aplausos)".
    3. Use bom senso: (risada) após piadas, (buzina) ou (transito) em menções a carros/cidade, (explosao) para impacto, (caixa) para dinheiro/vendas.
    4. Se o texto não pedir efeitos, retorne o texto original.

    TEXTO:
    "${text}"

    RESPOSTA (Apenas o texto com tags):
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
    });

    let finalText = response.text?.trim() || text;
    finalText = finalText.replace(/^["']|["']$/g, "").trim(); // Remove aspas extras se a IA colocar
    return finalText;
  } catch (e) {
    console.error("Erro no Auto SFX:", e);
    return text;
  }
};

// Função interna para chamar o TTS com Retry automático e Fallback Cruzado
const callTTS = async (textChunk: string, voiceName: string, isCustom: boolean): Promise<string> => {
    if (!textChunk.trim()) return "";

    const ai = getClient();
    // AUMENTADO PARA 5 TENTATIVAS devido a sobrecarga da API
    const MAX_RETRIES = 5;

    // Tratamento para variações de voz simuladas
    let effectiveVoice = voiceName;

    if (voiceName.includes('-')) {
        const parts = voiceName.split('-');
        effectiveVoice = parts[0]; 
    }

    // Lógica Custom Voice
    const customVoiceData = !Object.values(VoiceName).includes(effectiveVoice as VoiceName) && !voiceName.includes('-') 
        ? getCustomVoiceById(effectiveVoice) 
        : null;

    let lastError: any = null;

    // Loop de Tentativa (Retry)
    for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
        try {
            if (customVoiceData && customVoiceData.audioSampleBase64) {
                // MODO CLONAGEM (Modelo Nativo)
                const mimeType = getMimeTypeFromBase64(customVoiceData.audioSampleBase64, 'audio/wav');
                const base64Sample = customVoiceData.audioSampleBase64.split(',')[1] || customVoiceData.audioSampleBase64;

                const response = await ai.models.generateContent({
                    model: "gemini-2.5-flash-native-audio-preview-09-2025",
                    contents: {
                        parts: [
                            { inlineData: { mimeType: mimeType, data: base64Sample } },
                            { text: `Read this text exactly in Portuguese Brazil: "${textChunk}"` }
                        ]
                    },
                    config: { responseModalities: [Modality.AUDIO] }
                });
                return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
            } 

            // MODO TTS PADRÃO (Modelo TTS)
            const response = await ai.models.generateContent({
                model: "gemini-2.5-flash-preview-tts",
                contents: [{ parts: [{ text: textChunk }] }],
                config: {
                    responseModalities: ['AUDIO'],
                    speechConfig: {
                        voiceConfig: { prebuiltVoiceConfig: { voiceName: effectiveVoice } },
                    },
                },
            });
            return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";

        } catch (e: any) {
            console.warn(`Tentativa ${attempt} falhou:`, e.message);
            lastError = e;

            // Verifica se é erro 503 (Overloaded) ou 429 (Too Many Requests) de forma mais abrangente
            const isOverloaded = 
                e.message?.includes('503') || 
                e.message?.includes('overloaded') || 
                e.message?.includes('429') ||
                e.status === 503 ||
                (e.error && e.error.code === 503);

            if (isOverloaded && attempt < MAX_RETRIES) {
                // Backoff exponencial: 2s, 4s, 8s, 16s... + jitter aleatório
                const delay = Math.pow(2, attempt) * 1000 + (Math.random() * 1000); 
                console.log(`Servidor ocupado (503). Aguardando ${Math.round(delay)}ms para tentar novamente...`);
                await wait(delay);
                continue;
            }

            // SE ACABARAM AS TENTATIVAS E FOI ERRO 503, TENTA FALLBACK DE MODELO CRUZADO

            if (attempt === MAX_RETRIES) {

                // CASO 1: Era Voz Customizada (Modelo Nativo) -> Fallback para TTS Padrão (Kore)
                if (customVoiceData) {
                    console.warn("Clonagem de voz falhou (503). Ativando FALLBACK para voz padrão (Kore).");
                    try {
                        const fallbackResponse = await ai.models.generateContent({
                            model: "gemini-2.5-flash-preview-tts",
                            contents: [{ parts: [{ text: textChunk }] }],
                            config: {
                                responseModalities: ['AUDIO'],
                                speechConfig: {
                                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
                                },
                            },
                        });
                        return fallbackResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
                    } catch (fbErr) {
                         // Se falhar o fallback, joga o erro original
                         console.error("Fallback TTS falhou também.");
                    }
                } 

                // CASO 2: Era Voz Padrão (Modelo TTS) -> Fallback para Modelo Nativo (Flash Native Audio)
                // Isso usa uma rota diferente nos servidores do Google
                else {
                    console.warn("TTS Padrão falhou (503). Ativando FALLBACK para Modelo Nativo.");
                    try {
                        const fallbackResponse = await ai.models.generateContent({
                            model: "gemini-2.5-flash-native-audio-preview-09-2025",
                            contents: {
                                parts: [
                                    { text: `Speak the following text clearly and naturally in Portuguese (Brazil): "${textChunk}"` }
                                ]
                            },
                            config: { responseModalities: [Modality.AUDIO] }
                        });
                        return fallbackResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
                    } catch (fbErr) {
                        console.error("Fallback Nativo falhou também.");
                    }
                }

                // Se nenhum fallback funcionou, lança o erro para o usuário
                throw new Error("Servidores do Google sobrecarregados (503). Tente novamente em alguns instantes.");
            }
        }
    }

    throw lastError || new Error("Falha na geração de áudio.");
};

export const generateSpeech = async (rawText: string, voice: string): Promise<string> => {
  // 1. Detectar se há comandos de SFX: (comando)
  const sfxRegex = /(\(.*?\))/g;
  const parts = rawText.split(sfxRegex);

  // Se não houver SFX, fluxo normal rápido
  if (parts.length === 1) {
      return await callTTS(rawText, voice, false);
  }

  // 2. Processamento Híbrido (TTS + SFX)
  // Precisamos de um AudioContext temporário para decodificar e concatenar
  const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  const audioBuffers: AudioBuffer[] = [];

  for (const part of parts) {
      const segment = part.trim();
      if (!segment) continue;

      if (segment.startsWith('(') && segment.endsWith(')')) {
          // É um comando SFX
          const keyword = segment.slice(1, -1); // remove ( )
          console.log(`Gerando SFX: ${keyword}`);
          try {
             const sfxBuffer = await generateProceduralSFX(keyword, ctx);
             audioBuffers.push(sfxBuffer);
          } catch (e) {
             console.error(`Erro ao gerar SFX ${keyword}`, e);
          }
      } else {
          // É texto fala
          try {
             // Chamamos callTTS que agora tem RETRY automático e FALLBACK
             const ttsBase64 = await callTTS(segment, voice, false);
             if (ttsBase64) {
                 const ttsBuffer = await decodeAudioData(ttsBase64, ctx);
                 audioBuffers.push(ttsBuffer);
             }
          } catch (e) {
             console.error("Erro TTS no segmento", e);
             // Se falhar um segmento, lançamos erro para o usuário saber
             throw e;
          }
      }
  }

  // 3. Concatenar tudo
  const finalBuffer = concatenateAudioBuffers(audioBuffers, ctx);

  // 4. Converter de volta para Base64 (WAV) para manter compatibilidade com o resto do app
  const wavBlob = (await import("../utils/audioUtils")).audioBufferToWav(finalBuffer);

  return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onloadend = () => {
          const base64 = (reader.result as string).split(',')[1];
          resolve(base64);
      };
      reader.onerror = reject;
      reader.readAsDataURL(wavBlob);
  });
};

