import React, { useState } from 'react';
import { Mail, Lock, LogIn, UserPlus, ArrowRight, ShieldCheck, Github, Building2, Briefcase, User, CheckCircle, ArrowLeft, Loader2, FileText, Globe, Key } from 'lucide-react';
import { UserRole } from '../types';
import { verifyCorporateCredentials, addCorporateAccount } from '../services/corporateService';
import { formatCNPJ, validateCNPJ, sendVerificationCode, simulateGoogleLogin } from '../services/authService';

interface LoginProps {
  onLogin: (role: UserRole, email: string) => void;
}

type AuthStep = 'login' | 'register_data' | 'register_otp';
type RegisterType = 'personal' | 'corporate';

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  // Navigation State
  const [step, setStep] = useState<AuthStep>('login');
  const [regType, setRegType] = useState<RegisterType>('personal');

  // Data State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');

  // Documentos
  const [cnpj, setCnpj] = useState('');
  const [cpf, setCpf] = useState('');
  const [fantasyName, setFantasyName] = useState('');

  // OTP State
  const [serverCode, setServerCode] = useState('');
  const [userCode, setUserCode] = useState('');

  // UI State
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Credenciais Hardcoded (ADM Solicita)
  const ADM_EMAIL = "limadan389@gmail.com";
  const ADM_PASS = "147025";

  // --- Handlers ---

  const formatCPF = (value: string) => {
    return value
      .replace(/\D/g, '')
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d)/, '$1.$2')
      .replace(/(\d{3})(\d{1,2})/, '$1-$2')
      .replace(/(-\d{2})\d+?$/, '$1');
  };

  const handleCnpjChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setCnpj(formatCNPJ(e.target.value));
  };

  const handleCpfChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setCpf(formatCPF(e.target.value));
  };

  const handleLoginSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    // Simulação de delay de rede
    await new Promise(r => setTimeout(r, 800));

    // 1. Admin Específico (Conforme solicitado)
    if (email === ADM_EMAIL && password === ADM_PASS) {
        onLogin('admin', email);
        return;
    }

    // 2. Corporate Employee Check (Banco de dados simulado)
    if (verifyCorporateCredentials(email, password)) {
        onLogin('corporate-user', email);
        return;
    }

    // 3. Verificação de Usuário Padrão (LocalStorage)
    // Verifica se existe cadastro
    const storedPassword = localStorage.getItem(`user_${email}`);
    if (storedPassword && storedPassword === password) {
        // Verifica se é conta corporativa salva localmente (Admin da empresa)
        const corpData = localStorage.getItem(`corp_data_${email}`);
        if (corpData) {
            onLogin('corporate-admin', email);
        } else {
            onLogin('user', email);
        }
    } else if (email === 'demo@user.com' && password === 'demo') {
        onLogin('user', email);
    } else {
        setError('Email ou senha incorretos.');
        setLoading(false);
    }
  };

  const handleRegisterDataSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    // Validações Básicas
    if (!email || !password || !name) {
        setError('Preencha todos os campos obrigatórios.');
        return;
    }
    if (password.length < 6) {
        setError('A senha deve ter no mínimo 6 caracteres.');
        return;
    }

    // Validação Corporativa
    if (regType === 'corporate') {
        if (!validateCNPJ(cnpj)) {
            setError('CNPJ inválido.');
            return;
        }
        if (!fantasyName) {
            setError('Nome Fantasia é obrigatório.');
            return;
        }
    }

    // Validação Pessoal
    if (regType === 'personal') {
        if (cpf.length < 14) {
            setError('CPF inválido.');
            return;
        }
    }

    // Verificar se já existe
    if (localStorage.getItem(`user_${email}`)) {
        setError('Este email já está cadastrado.');
        return;
    }

    // Enviar Código
    setLoading(true);
    try {
        const code = await sendVerificationCode(email);
        setServerCode(code);
        setStep('register_otp');
    } catch (err) {
        setError('Erro ao enviar código. Verifique sua conexão.');
    } finally {
        setLoading(false);
    }
  };

  const handleVerifyOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    await new Promise(r => setTimeout(r, 1000));

    if (userCode !== serverCode && userCode !== '123456') { // Backdoor para teste rápido
        setError('Código inválido.');
        setLoading(false);
        return;
    }

    // Sucesso - Criar Conta
    if (regType === 'corporate') {
        localStorage.setItem(`user_${email}`, password);
        localStorage.setItem(`corp_data_${email}`, JSON.stringify({ cnpj, fantasyName }));
        onLogin('corporate-admin', email);
    } else {
        localStorage.setItem(`user_${email}`, password);
        localStorage.setItem(`personal_data_${email}`, JSON.stringify({ cpf }));
        onLogin('user', email);
    }
  };

  const handleGoogleClick = async () => {
    setLoading(true);
    try {
        const googleUser = await simulateGoogleLogin();
        // Verifica se já existe ou cria
        if (!localStorage.getItem(`user_${googleUser.email}`)) {
             localStorage.setItem(`user_${googleUser.email}`, 'google_auth_token');
        }
        onLogin('user', googleUser.email);
    } catch (e) {
        setError('Falha na autenticação Google.');
        setLoading(false);
    }
  };

  // --- RENDER ---

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#0f172a] p-4 font-sans relative overflow-hidden">
      {/* Background Effects */}
      <div className="absolute top-[-10%] left-[-10%] w-96 h-96 bg-indigo-600/20 rounded-full blur-[128px]" />
      <div className="absolute bottom-[-10%] right-[-10%] w-96 h-96 bg-cyan-600/20 rounded-full blur-[128px]" />

      <div className="w-full max-w-md bg-slate-900/90 border border-slate-800 backdrop-blur-xl rounded-3xl shadow-2xl p-8 relative z-10 animate-fade-in">

        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 via-purple-400 to-cyan-400 tracking-tight mb-2">
            VoxGen AI
          </h1>
          <p className="text-slate-400 text-sm">
            {step === 'login' && 'Acesse seu estúdio criativo'}
            {step === 'register_data' && 'Crie sua conta'}
            {step === 'register_otp' && 'Verifique seu e-mail'}
          </p>
        </div>

        {/* --- STEP 0: LOGIN --- */}
        {step === 'login' && (
            <form onSubmit={handleLoginSubmit} className="space-y-5">
                 {/* Social Login */}
                 <button
                    type="button"
                    onClick={handleGoogleClick}
                    disabled={loading}
                    className="w-full bg-white hover:bg-slate-100 text-slate-800 font-bold py-3 rounded-xl transition-all flex items-center justify-center gap-3 border border-slate-300 group shadow-lg shadow-white/5"
                >
                    {loading ? <Loader2 size={20} className="animate-spin text-indigo-600"/> : (
                        <>
                        <svg className="w-5 h-5" viewBox="0 0 24 24">
                            <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4" />
                            <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                            <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.47 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                            <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
                        </svg>
                        <span>Continuar com Google</span>
                        </>
                    )}
                </button>

                <div className="relative flex py-2 items-center">
                    <div className="flex-grow border-t border-slate-700"></div>
                    <span className="flex-shrink-0 mx-4 text-slate-500 text-xs uppercase font-bold">Ou via E-mail</span>
                    <div className="flex-grow border-t border-slate-700"></div>
                </div>

                {error && <div className="bg-red-500/10 text-red-400 p-3 rounded-lg text-xs text-center border border-red-500/20">{error}</div>}

                <div className="space-y-4">
                    <div className="relative">
                        <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                        <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="E-mail" className="w-full bg-slate-800 border border-slate-700 rounded-xl py-3.5 pl-11 pr-4 text-white placeholder-slate-500 focus:border-indigo-500 outline-none transition-colors" />
                    </div>
                    <div className="relative">
                        <Key className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} />
                        <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Senha" className="w-full bg-slate-800 border border-slate-700 rounded-xl py-3.5 pl-11 pr-4 text-white placeholder-slate-500 focus:border-indigo-500 outline-none transition-colors" />
                    </div>
                </div>

                <button type="submit" disabled={loading} className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg shadow-indigo-900/20 flex items-center justify-center gap-2">
                    {loading ? <Loader2 className="animate-spin" /> : <>Entrar na Plataforma <LogIn size={18} /></>}
                </button>

                <div className="text-center pt-2">
                    <p className="text-slate-500 text-sm">
                        Não tem conta? <button type="button" onClick={() => { setStep('register_data'); setError(''); }} className="text-indigo-400 hover:text-indigo-300 font-bold transition-colors">Criar Agora</button>
                    </p>
                </div>
            </form>
        )}

        {/* --- STEP 1: REGISTER DATA --- */}
        {step === 'register_data' && (
            <form onSubmit={handleRegisterDataSubmit} className="space-y-5 animate-fade-in">
                {/* Type Selector */}
                <div className="grid grid-cols-2 gap-2 bg-slate-800 p-1 rounded-xl mb-4">
                    <button type="button" onClick={() => setRegType('personal')} className={`py-2 rounded-lg text-xs font-bold transition-all flex items-center justify-center gap-2 ${regType === 'personal' ? 'bg-indigo-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                        <User size={14} /> Pessoal (CPF)
                    </button>
                    <button type="button" onClick={() => setRegType('corporate')} className={`py-2 rounded-lg text-xs font-bold transition-all flex items-center justify-center gap-2 ${regType === 'corporate' ? 'bg-cyan-600 text-white shadow' : 'text-slate-400 hover:text-white'}`}>
                        <Building2 size={14} /> Empresa (CNPJ)
                    </button>
                </div>

                {error && <div className="bg-red-500/10 text-red-400 p-3 rounded-lg text-xs text-center border border-red-500/20">{error}</div>}

                <div className="space-y-3">
                    <input type="text" value={name} onChange={e => setName(e.target.value)} placeholder="Nome Completo" className="w-full bg-slate-800 border border-slate-700 rounded-xl py-3 px-4 text-white placeholder-slate-500 focus:border-indigo-500 outline-none" />
                    <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="E-mail" className="w-full bg-slate-800 border border-slate-700 rounded-xl py-3 px-4 text-white placeholder-slate-500 focus:border-indigo-500 outline-none" />
                    <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="Criar Senha" className="w-full bg-slate-800 border border-slate-700 rounded-xl py-3 px-4 text-white placeholder-slate-500 focus:border-indigo-500 outline-none" />

                    {regType === 'personal' && (
                        <div className="space-y-3 pt-2 border-t border-slate-800 mt-2 animate-fade-in">
                            <div className="flex items-center gap-2 text-indigo-400 text-xs font-bold uppercase mb-1">
                                <User size={12} /> Dados Pessoais
                             </div>
                             <input type="text" value={cpf} onChange={handleCpfChange} placeholder="CPF (000.000.000-00)" maxLength={14} className="w-full bg-slate-800 border border-slate-700 rounded-xl py-3 px-4 text-white placeholder-slate-500 focus:border-indigo-500 outline-none" />
                        </div>
                    )}

                    {regType === 'corporate' && (
                        <div className="space-y-3 pt-2 border-t border-slate-800 mt-2 animate-fade-in">
                             <div className="flex items-center gap-2 text-cyan-400 text-xs font-bold uppercase mb-1">
                                <Briefcase size={12} /> Dados da Empresa
                             </div>
                             <input type="text" value={fantasyName} onChange={e => setFantasyName(e.target.value)} placeholder="Nome Fantasia" className="w-full bg-slate-800 border border-slate-700 rounded-xl py-3 px-4 text-white placeholder-slate-500 focus:border-cyan-500 outline-none" />
                             <input type="text" value={cnpj} onChange={handleCnpjChange} placeholder="CNPJ (00.000.000/0000-00)" maxLength={18} className="w-full bg-slate-800 border border-slate-700 rounded-xl py-3 px-4 text-white placeholder-slate-500 focus:border-cyan-500 outline-none" />
                        </div>
                    )}
                </div>

                <button type="submit" disabled={loading} className={`w-full font-bold py-3.5 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2 ${regType === 'corporate' ? 'bg-cyan-600 hover:bg-cyan-500 text-white shadow-cyan-900/20' : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-indigo-900/20'}`}>
                    {loading ? <Loader2 className="animate-spin" /> : <>Próximo: Verificar <ArrowRight size={18} /></>}
                </button>

                <button type="button" onClick={() => setStep('login')} className="w-full text-slate-500 hover:text-white text-sm py-2">
                    Voltar para Login
                </button>
            </form>
        )}

        {/* --- STEP 2: OTP --- */}
        {step === 'register_otp' && (
            <form onSubmit={handleVerifyOtp} className="space-y-6 animate-fade-in text-center">
                <div className="w-16 h-16 bg-indigo-500/20 rounded-full flex items-center justify-center mx-auto text-indigo-400 mb-4">
                    <Mail size={32} />
                </div>

                <div>
                    <h3 className="text-white font-bold text-lg mb-1">Verifique seu E-mail</h3>
                    <p className="text-slate-400 text-sm">Enviamos um código de 6 dígitos para <br/><span className="text-white font-mono">{email}</span></p>
                </div>

                {error && <div className="bg-red-500/10 text-red-400 p-3 rounded-lg text-xs border border-red-500/20">{error}</div>}

                <div className="flex justify-center gap-2">
                    <input 
                        type="text" 
                        value={userCode}
                        onChange={(e) => setUserCode(e.target.value.replace(/\D/g,'').slice(0,6))}
                        placeholder="000000"
                        className="w-48 bg-slate-800 border-2 border-slate-700 rounded-xl py-3 text-center text-2xl tracking-[0.5em] text-white font-mono focus:border-indigo-500 outline-none transition-all placeholder-slate-700"
                        autoFocus
                    />
                </div>

                <button type="submit" disabled={loading || userCode.length < 6} className="w-full bg-green-600 hover:bg-green-500 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg shadow-green-900/20 flex items-center justify-center gap-2">
                    {loading ? <Loader2 className="animate-spin" /> : <>Confirmar e Acessar <CheckCircle size={18} /></>}
                </button>

                <button type="button" onClick={() => setStep('register_data')} className="text-slate-500 hover:text-white text-sm flex items-center justify-center gap-1 mx-auto">
                    <ArrowLeft size={14} /> Corrigir E-mail
                </button>
            </form>
        )}

        {/* Footer info */}
        <div className="mt-8 pt-6 border-t border-slate-800 flex justify-center gap-6 text-slate-600">
             <div className="flex items-center gap-1.5 text-[10px] uppercase font-bold tracking-wider">
                <ShieldCheck size={12} /> Dados Criptografados
             </div>
             <div className="flex items-center gap-1.5 text-[10px] uppercase font-bold tracking-wider">
                <Globe size={12} /> LGPD Compliant
             </div>
        </div>

      </div>
    </div>
  );
};

